public int countTrees(int[][] pairs) {
    int nodes = pairs.length + 1;
    int[] in_degrees = new int[nodes];
    for (int[] pair : pairs) {
        in_degrees[pair[1]]++;
    }

    int res = 1;
    for (int i = 1; i < nodes; i++) {
        res *= in_degrees[i];
    }

    return res;
}
```

